state n = 0;
label n;
row {
  button "1" { n = n * 10 + 1; }
  button "2" { n = n * 10 + 2; }
  button "3" { n = n * 10 + 3; }
}

state s = 1;
label "step " + s;
row {
  button "next" { if s < 3 { s = s + 1; } }
  button "back" { if s > 1 { s = s - 1; } }
}

state entry = 0;
state stored = 0;
state result = 0;
label result;
row {
  button "2" { entry = 2; }
  button "3" { entry = 3; }
  button "plus" { stored = entry; entry = 0; }
  button "=" { result = stored + entry; }
}

state n = 0;
button "+1" { n = n + 1; }
if n % 2 == 0 { label n; } else { label "odd"; }

state a = 0;
state b = 0;
row {
  button "a+" { a = a + 1; }
  button "b+" { b = b + 1; }
}
label a - b;

state n = 0;
state prev = 0;
label n;
row {
  button "+5" { prev = n; n = n + 5; }
  button "undo" { n = prev; }
}

state n = 0;
state up = true;
label n;
button "step" {
  if up { n = n + 2; if n >= 6 { up = false; } }
  else { n = n - 2; if n <= 0 { up = true; } }
}

state u = "";
state ok = false;
input u;
button "login" { if u != "" { ok = true; } }
if ok { label "Welcome back"; }

state t = 0;
label t;
button "add 3" { t = t + 3; }
if t % 2 == 0 { label "even"; } else { label "odd"; }

state editing = false;
state s = "";
button "mode" { if editing { editing = false; } else { editing = true; } }
if editing { label "edit"; input s; label "typing: " + s; } else { label "view"; }

state armed = false;
state off = false;
row {
  button "arm" { armed = true; }
  button "launch" { if armed { off = true; } }
}
if off { label "LIFTOFF"; }

state t = 0;
state c = 0;
row {
  button "add 4" { t = t + 4; c = c + 1; }
  button "add 8" { t = t + 8; c = c + 1; }
}
if c == 0 { label 0; } else { label t / c; }

state n = 1;
label n;
button "next" { n = n + 1; if n > 3 { n = 1; } }

state n = 1;
label n;
button "double" { n = n * 2; if n > 100 { n = 1; } }

state f = "";
state l = "";
input f;
input l;
label l + ", " + f;

state coins = 0;
state got = false;
label "coins: " + coins;
row {
  button "insert coin" { coins = coins + 1; }
  button "buy" { if coins >= 2 { coins = coins - 2; got = true; } }
}
if got { label "dispensed"; }
